fetchContent (force: boolean) {
  if (typeof this.content === 'function' && this.$_isShown &&
    (force || (!this.$_loading && this.asyncContent == null))) {
    this.asyncContent = null
    this.$_loading = true
    const fetchId = ++this.$_fetchId
    const result = this.content(this)
    if (result.then) {
      result.then(res => this.onResult(fetchId, res))
    } else {
      this.onResult(fetchId, result)
    }
  }
}

created() {
  const handleDocsSetToc = toc => {
    this.expanded = false
    // Update the TOC content
    this.toc = toc
  }

  this.$root.$on('docs-set-toc', handleDocsSetToc)

  this.$once('hook:beforeDestroy', () => {
    this.$root.$off('docs-set-toc', handleDocsSetToc)
  })
}

created() {
  // Create private non-reactive props
  this.$_filterTimer = null

  // In a `$nextTick()` to ensure `toc.vue` is created first
  this.$nextTick(() => {
    const key = `${this.$route.name}_${this.$route.params.slug || ''}`
    const toc =
      TOC_CACHE[key] || (TOC_CACHE[key] = updateMetaTOC(this.baseTOC || {}, this.meta || null))
    this.$root.$emit('docs-set-toc', toc)
  })
}

badgeStyle() {
  const { computedSize: size, badgeTop, badgeLeft, badgeOffset } = this
  const offset = badgeOffset || '0px'
  return {
    fontSize: SIZES.indexOf(size) === -1 ? `calc(${size} * ${BADGE_FONT_SIZE_SCALE} )` : null,
    top: badgeTop ? offset : null,
    bottom: badgeTop ? null : offset,
    left: badgeLeft ? offset : null,
    right: badgeLeft ? null : offset
  }
}

selectedYMD(newYMD, oldYMD) {
  // TODO:
  //   Should we compare to `formatYMD(this.value)` and emit
  //   only if they are different?
  if (newYMD !== oldYMD) {
    this.$emit(MODEL_EVENT_NAME, this.valueAsDate ? parseYMD(newYMD) || null : newYMD || '')
  }
}

onNowButton() {
  const now = new Date()
  const hours = now.getHours()
  const minutes = now.getMinutes()
  const seconds = this.showSeconds ? now.getSeconds() : 0
  const value = [hours, minutes, seconds].map(v => `00${v || ''}`.slice(-2)).join(':')
  this.setAndClose(value)
}

(h, ctx) => {
  const $footer = ctx.normalizeSlot(SLOT_NAME_FOOTER, ctx.slotScope)
  if (!$footer) {
    return h()
  }

  return h(
    ctx.footerTag,
    {
      staticClass: `${CLASS_NAME}-footer`,
      class: ctx.footerClass,
      key: 'footer'
    },
    [$footer]
  )
}

computedAttrs() {
  return {
    ...this.bvAttrs,
    id: this.safeId(),
    tabindex: '-1',
    role: 'dialog',
    'aria-modal': this.backdrop ? 'true' : 'false',
    'aria-hidden': this.localShow ? null : 'true',
    'aria-label': this.ariaLabel || null,
    'aria-labelledby': this.ariaLabelledby || this.titleId || null
  }
}

[MODEL_PROP_NAME_SHOW](newValue, oldValue) {
  if (newValue !== oldValue && newValue !== this.localShow && this.$_toolpop) {
    if (newValue) {
      this.$_toolpop.show()
    } else {
      // We use `forceHide()` to override any active triggers
      this.$_toolpop.forceHide()
    }
  }
}

listenForFocusIn(newValue, oldValue) {
  if (newValue !== oldValue) {
    eventOff(this.focusInElement, 'focusin', this._focusInHandler, EVENT_OPTIONS_NO_CAPTURE)
    if (newValue) {
      eventOn(this.focusInElement, 'focusin', this._focusInHandler, EVENT_OPTIONS_NO_CAPTURE)
    }
  }
}

handleAutofocus() {
  this.$nextTick(() => {
    requestAF(() => {
      let el = this.$el
      if (this.autofocus && isVisible(el)) {
        if (!matches(el, SELECTOR)) {
          el = select(SELECTOR, el)
        }
        attemptFocus(el)
      }
    })
  })
}

locale => {
  // Determines if the locale is RTL (only single locale supported)
  const parts = toString(locale)
    .toLowerCase()
    .replace(RX_STRIP_LOCALE_MODS, '')
    .split('-')
  const locale1 = parts.slice(0, 2).join('-')
  const locale2 = parts[0]
  return arrayIncludes(RTL_LANGS, locale1) || arrayIncludes(RTL_LANGS, locale2)
}

() => {
  if (!filter.value) {
    return items
  }
  return items.filter(
    (item) =>
      item.first_name.toLowerCase().includes(lcFilter.value) ||
      item.last_name.toLowerCase().includes(lcFilter.value) ||
      item.age.toLocaleString().includes(lcFilter.value)
  )
}

() => {
  const aspect = String(props.aspect)
  let ratio
  if (/^\d+(\.\d*)?[/:x]\d+(\.\d*)?$/.test(aspect)) {
    const [width = 1, height = 1] = aspect.split(/[/:x]/).map((v) => Number.parseFloat(v) || 1)
    ratio = width / height
  } else {
    ratio = Number.parseFloat(aspect) || 1
  }
  return `${100 / Math.abs(ratio)}%`
}

(el: Element) => {
  inCollapse = true
  requestAnimationFrame(() => {
    if (props.horizontal) {
      ;(el as HTMLElement).style.width = `${(el as HTMLElement).scrollWidth}px`
    } else {
      ;(el as HTMLElement).style.height = `${(el as HTMLElement).scrollHeight}px`
    }
  })
}

(el: HTMLButtonElement) => {
  const isElement = el && el.nodeType === Node.ELEMENT_NODE
  const hasAttr = isElement ? el.hasAttribute('disabled') : null
  const hasClass = isElement && el.classList ? el.classList.contains('disabled') : false

  return !isElement || el.disabled || hasAttr || hasClass
}

() => [
  {
    'active': isActive.value,
    'show': show.value,
    'card-body': parentData?.card.value && props.noBody === false,
    'fade': !parentData?.noFade.value,
  },
  show.value ? parentData?.activeTabClass.value : parentData?.inactiveTabClass.value,
  parentData?.tabClass.value,
]

switchTo(newIndex: number) {
    if (newIndex === this.scrollIndex || isNaN(newIndex)) { return }

    if (this.settings.repeat) {
        newIndex = mod(newIndex, this.total + 1)
    }
    newIndex = bound(newIndex, 0, this.total)
    this.scrollIndex = newIndex
    if (!this.asIndicator && this.modelValue !== newIndex) {
        this.$emit('update:modelValue', newIndex)
    } else if (this.scrollIndex !== newIndex) {
        this.$emit('updated:scroll', newIndex)
    }
}

style() {
    return {
        backgroundImage:
            `linear-gradient(90deg, ${this.startColor} 0%, ${this.endColor} 100%),
            linear-gradient(45deg, #c7c7c7 25%, transparent 25%, transparent 75%, #c7c7c7 75%, #c7c7c7),
            linear-gradient(45deg, #c7c7c7 25%, transparent 25%, transparent 75%, #c7c7c7 75%, #c7c7c7)`,
        backgroundSize: '100% 100%, 1em 1em, 1em 1em',
        backgroundPosition: '0 0, .5em .5em, 0 0'
    }
}

slThumbStyle() {
    let { hue, saturation, lightness } = this
    saturation = Math.max(0, Math.min(1, saturation))
    lightness = Math.max(0, Math.min(1, lightness))
    return {
        background: `hsl(${hue}deg, ${saturation * 100}%, ${lightness * 100}%)`,
        left: `${saturation * 100}%`,
        top: `${(1 - lightness) * 100}%`
    }
}

formatYYYYMMDD(value: Date | null | undefined) {
    const date = new Date(value!)
    if (value && !isNaN(date.valueOf())) {
        const year = date.getFullYear()
        const month = date.getMonth() + 1
        const day = date.getDate()
        return year + '-' +
            ((month < 10 ? '0' : '') + month) + '-' +
            ((day < 10 ? '0' : '') + day)
    }
    return ''
}

eventsInThisWeek(week: Date[]) {
    return this.eventsInThisMonth.filter((event) => {
        // TODO: we may do `new Date(event.date)` instead
        const stripped = new Date(Date.parse(event.date + ''))
        stripped.setHours(0, 0, 0, 0)
        const timed = stripped.getTime()

        return week.some((weekDate) => weekDate.getTime() === timed)
    })
}

changeFocus(day: Date, inc: number) {
    const nextDay = new Date(day.getTime())
    nextDay.setDate(day.getDate() + inc)
    while (
        (!this.minDate || nextDay > this.minDate) &&
        (!this.maxDate || nextDay < this.maxDate) &&
        !this.selectableDate(nextDay)
    ) {
        nextDay.setDate(nextDay.getDate() + Math.sign(inc))
    }
    this.setRangeHoverEndDate(nextDay)
    this.$emit('change-focus', nextDay)
}

onInternalValueUpdate() {
    if (this.isRange) {
        this.isThumbReversed = this.value1! > this.value2!
    }
    if (!this.lazy || !this.dragging) {
        this.emitValue('update:modelValue')
    }
    if (this.dragging) {
        this.emitValue('dragging')
    }
}

checkSort() {
    if (this.newColumns.length && this.firstTimeSort) {
        this.initSort()
        this.firstTimeSort = false
    } else if (this.newColumns.length) {
        if (toRaw(this.currentSortColumn) !== BLANK_COLUMN) {
            for (let i = 0; i < this.newColumns.length; i++) {
                if (this.newColumns[i].field === this.currentSortColumn.field) {
                    this.currentSortColumn = this.newColumns[i]
                    break
                }
            }
        }
    }
}

getSaturation() {
    const [red, green, blue] = Array.from(this.$channels).map((c) => c / 255)
    const [min, max] = [Math.min(red, green, blue), Math.max(red, green, blue)]
    const delta = max - min

    return delta !== 0
        ? Math.round(delta / (1 - Math.abs(2 * this.lightness - 1)) * 100) / 100
        : 0
}

function () {
    return (
        typeof window !== 'undefined' &&
        (window.navigator.userAgent.match(/iPhone|iPad|iPod/i) ||
            (window.navigator.platform === 'MacIntel' &&
                window.navigator.maxTouchPoints > 1))
    )
}
